import { createStore } from 'vuex'

const setLocalCartList = (state) => {
  const { cartList } = state
  const cartListString = JSON.stringify(cartList)
  localStorage.cartList = cartListString
}

const getLocalCartList = () => {
  return localStorage.cartList ? JSON.parse(localStorage.cartList) : {}
}

export default createStore({
  state: {
    // { shopId: { shopName: '', productList: { productId: '' } } }
    // 第一层级是商铺的id
    // shopId: {
    //   shopName: '沃尔玛',
    //   productList: {
    //     productId: {
    //     _id: '1',
    //     name: '番茄250g/份',
    //     imgUrl: 'http://www.dell-lee.com/imgs/vue3/tomato.png',
    //     sales: 10,
    //     price: 33.6,
    //     oldPrice: 39.6,
    //     count: 2
    //   }
    //   }
    // }
    cartList: getLocalCartList()
  },
  mutations: {
    changeCartItemInfo(state, payload) {  // 购物车 添加/减少 逻辑
      const { shopId, productId, productInfo } = payload
      let shopInfo = state.cartList[shopId] ?? {
        shopName: '', productList: {}
      }
      let product = shopInfo.productList[productId]
      if (!product) {
        productInfo.count = 0
        product = productInfo
      }
      product.count = product.count + payload.num
      // if (payload.num > 0) { product.check = true }
      // if (product.count < 0) { product.count = 0 }
      ;(payload.num > 0) && (product.check = true)  // 等价于上面的写法
      ;(product.count < 0) && (product.count = 0)
      shopInfo.productList[productId] = product
      state.cartList[shopId] = shopInfo
      setLocalCartList(state)
      // console.log('state.cartList >>> ', state.cartList)
    },
    changeCartItemCheck(state, payload) {  // 修改购物车内商品 选中/取消 逻辑
      const { shopId, productId } = payload
      const product = state.cartList[shopId].productList[productId]
      product.check = !product.check
      setLocalCartList(state)
    },
    cleanCartProducts(state, payload) {  // 清空购物车逻辑
      const { shopId } = payload
      state.cartList[shopId].productList = {}
      setLocalCartList(state)
    },
    setCartItemsChecked(state, payload) {  // 全选购物车逻辑
      const { shopId } = payload
      const products = state.cartList[shopId].productList
      if (products) {
        for (let key in products) {
          const product = products[key]
          product.check = true
        }
      }
      setLocalCartList(state)
    },
    changeShopName(state, payload) {  // 修改商铺名
      const { shopId, shopName } = payload
      const shopInfo = state.cartList[shopId] || {
        shopName: '', productList: {}
      }
      shopInfo.shopName = shopName
      state.cartList[shopId] = shopInfo
      setLocalCartList(state)
    },
    clearCartData(state, shopId) {  // 确认下单后购物车内容清空
      state.cartList[shopId].productList = {}
    }
  },
  actions: {
  },
  modules: {
  }
})
